const express = require('express');
const { sendError } = require('../../lib/errors');
const projectService = require('./service');

const router = express.Router();

router.get('/', (req, res) => {
  const projects = projectService.getAllProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name || typeof name !== 'string' || name.trim() === '') {
    return sendError(res, 400, 'INVALID_NAME', 'Name must be a non-empty string');
  }

  const project = projectService.createProject(name);
  res.status(201).json({ project });
});

module.exports = router;

const { randomUUID } = require('node:crypto');

let projects = {};

function getAllProjects() {
  return Object.values(projects);
}

function createProject(name) {
  const projectId = randomUUID();
  const project = { id: projectId, name, tasks: [], members: [] };
  projects[projectId] = project;
  return project;
}

module.exports = {
  getAllProjects,
  createProject,
};

const express = require('express');
const { sendError } = require('../../lib/errors');
const taskService = require('./service');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.projectId;
  let tasks = taskService.getAllTasks(projectId);

  if (req.query.status) {
    tasks = tasks.filter(task => task.status === req.query.status);
  }

  res.json({ tasks });
});

router.post('/', (req, res) => {
  const projectId = req.projectId;
  const { title } = req.body;
  if (!title || typeof title !== 'string' || title.trim() === '') {
    return sendError(res, 400, 'INVALID_TITLE', 'Title must be a non-empty string');
  }

  const task = taskService.createTask(projectId, title);
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const projectId = req.projectId;
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }

  const task = taskService.updateTask(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }

  res.json({ task });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const projectService = require('../projects/service');

function getAllTasks(projectId) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  return project ? project.tasks : [];
}

function createTask(projectId, title) {
  const task = { id: randomUUID(), title, status: 'todo' };
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (project) {
    project.tasks.push(task);
  }
  return task;
}

function updateTask(projectId, taskId, status) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }

  const taskIndex = project.tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }

  project.tasks[taskIndex].status = status;
  return project.tasks[taskIndex];
}

module.exports = {
  getAllTasks,
  createTask,
  updateTask,
};

const express = require('express');
const { sendError } = require('./lib/errors');
const projectRoutes = require('./modules/projects/routes');
const memberRoutes = require('./modules/members/routes');
const taskRoutes = require('./modules/tasks/routes');
const commentRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectRoutes);

app.use('/projects/:projectId/members', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
}, memberRoutes);

app.use('/projects/:projectId/tasks', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
}, taskRoutes);

app.use('/projects/:projectId/tasks/:taskId/comments', (req, res, next) => {
  req.taskId = req.params.taskId;
  next();
}, commentRoutes);

app.use((err, req, res, next) => {
  console.error(err.stack);
  sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
});

module.exports = app;
